@app.route("/admin/tokens", methods=["POST"])
def create_token():
    payload = request.get_json(silent=True) or {}
    token = payload.get("token")
    subject = payload.get("subject")
    scope = payload.get("scope", "")

    if not token:
        return jsonify({"error": "token is required"}), 400

    db = get_db()
    try:
        db.execute(
            """
            INSERT INTO access_tokens (token, subject, scope, revoked)
            VALUES (?, ?, ?, 0)
            """,
            (token, subject, scope),
        )
        db.commit()
    except sqlite3.IntegrityError:
        return jsonify({"error": "token already exists"}), 409

    return jsonify({"created": True, "token": token}), 201


@app.route("/admin/tokens/<token>", methods=["DELETE"])
def revoke_token(token):
    db = get_db()
    result = db.execute(
        """
        UPDATE access_tokens
        SET revoked = 1
        WHERE token = ?
        """,
        (token,),
    )
    db.commit()

